Perfect! I've gathered all the information. Here's the complete exploration of the workspace implementation:

## FULL FILE CONTENTS

### 1. `src/app/workspace/page.tsx` - Main Workspace Page
```typescript
"use client";

import { useEffect, useState, useMemo } from "react";
import { useLanguageStore } from "@/store/language-store";
import { useRouter } from "next/navigation";
import { SiteHeader } from "@/components/layout/site-header";
import { ProCard } from "@/components/workspace/pro-card";
import { FloatingDock } from "@/components/workspace/floating-dock";
import { DossierSettingsDialog } from "@/components/workspace/dossier-settings-dialog";
import { cn } from "@/lib/utils";

interface Project {
    id: string;
    title?: string;
    text: string;
    description?: string;
    color?: string;
    globalScore?: number;
    recommendation?: string;
    confidenceLevel?: string;
    viabilityScore?: number;
    classification?: string;
    timestamp: string;
    isDemo?: boolean;
    analysis?: any;
}

function getProjectDecision(p: Project): string {
    return p.recommendation ?? p.classification ?? "DRAFT";
}

function getProjectTitle(p: Project): string {
    return p.title ?? p.text;
}

export default function WorkspacePage() {
    const { t } = useLanguageStore();
    const router = useRouter();

    const [projects, setProjects] = useState<Project[]>([]);
    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    const [searchQuery, setSearchQuery] = useState("");
    const [activeFilter, setActiveFilter] = useState<string>("ALL");
    const [sortBy, setSortBy] = useState<string>("date");

    // Settings dialog state
    const [settingsProject, setSettingsProject] = useState<Project | null>(null);
    const [settingsOpen, setSettingsOpen] = useState(false);

    // Initial Load Logic
    useEffect(() => {
        const currentIdea = localStorage.getItem("k3rn_active_project");
        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");

        if (currentIdea) {
            const idea = JSON.parse(currentIdea);
            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
            if (!exists) {
                const newProject: Project = {
                    id: idea.id || crypto.randomUUID(),
                    title: idea.title,
                    text: idea.text || "",
                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
                    recommendation: idea.recommendation ?? idea.analysis?.classification,
                    confidenceLevel: idea.confidenceLevel,
                    viabilityScore: idea.viabilityScore ?? idea.analysis?.viabilityScore,
                    classification: idea.classification ?? idea.analysis?.classification,
                    timestamp: idea.timestamp,
                    isDemo: idea.isDemo,
                    analysis: idea.analysis,
                };
                storedProjects.unshift(newProject);
                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
                localStorage.removeItem("k3rn_active_project");
            }
        }

        if (storedProjects.length === 0) {
            const mocks: Project[] = [
                { id: "1", title: "Drone Fleet SaaS Platform", text: "Plateforme SaaS de gestion de flottes de drones autonomes", globalScore: 92, recommendation: "GO", timestamp: new Date().toISOString(), isDemo: true, description: "A comprehensive solution for autonomous drone logistics, featuring real-time telemetry, AI-driven pathfinding, and predictive maintenance." },
                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true, description: "Attempting to tokenize IP rights on the blockchain. Initial market validation suggests low demand." },
                { id: "3", title: "AI Film Script Generator", text: "IA générative pour scripts de films", globalScore: 78, recommendation: "EXPLORE", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true, description: "Leveraging LLMs for creative writing assistance. The prototype shows promise but lacks structure." },
                { id: "4", title: "MeowNet - Social Network for Cats", text: "Réseau social pour chats (MeowNet)", globalScore: 22, recommendation: "PARK", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true, description: "Niche social network. Market size is questionable despite high engagement potential." },
                { id: "5", title: "Quantum Encryption Key", text: "Clé de chiffrement quantique", globalScore: 88, recommendation: "GO", timestamp: new Date(Date.now() - 500000000).toISOString(), isDemo: true, description: "Next-gen security infrastructure for fintech. Critical need in the post-quantum era." },
            ];
            setProjects(mocks);
        } else {
            setProjects(storedProjects);
        }
    }, []);

    const filteredProjects = useMemo(() => {
        let result = projects.filter((p) => {
            const q = searchQuery.toLowerCase();
            const matchesSearch =
                getProjectTitle(p).toLowerCase().includes(q) ||
                p.text.toLowerCase().includes(q) ||
                getProjectDecision(p).toLowerCase().includes(q);

            const matchesFilter = activeFilter === "ALL" || getProjectDecision(p) === activeFilter;

            return matchesSearch && matchesFilter;
        });

        // Sort
        if (sortBy === "score") {
            result = [...result].sort((a, b) => (b.globalScore ?? 0) - (a.globalScore ?? 0));
        } else {
            result = [...result].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
        }

        return result;
    }, [projects, searchQuery, activeFilter, sortBy]);

    // Save settings for a project
    function handleSaveSettings(updates: { title?: string; description?: string; color?: string }) {
        if (!settingsProject) return;
        const updated = projects.map((p) =>
            p.id === settingsProject.id ? { ...p, ...updates } : p
        );
        setProjects(updated);
        // Persist to localStorage (skip if all demo)
        const nonDemo = updated.filter((p) => !p.isDemo);
        if (nonDemo.length > 0 || updated.some((p) => p.isDemo && (updates.title || updates.description || updates.color))) {
            localStorage.setItem("k3rn_projects", JSON.stringify(updated));
        }
    }

    return (
        <div className="min-h-screen bg-background text-foreground font-sans selection:bg-[--color-brand-primary]/30 flex flex-col overflow-x-hidden">
            <SiteHeader variant="app" />

            <div className="relative z-10 flex-1 pt-24 pb-40 px-6 md:px-12 w-full max-w-[1600px] mx-auto">

                {/* Header */}
                <div className="flex justify-between items-end mb-12">
                    <div>
                        <h1 className="text-3xl font-medium tracking-tight text-[--color-text-primary] mb-2">
                            Dossiers
                        </h1>
                        <p className="text-[--color-text-muted] text-sm font-medium">
                            {filteredProjects.length} projet{filteredProjects.length !== 1 ? "s" : ""} actif{filteredProjects.length !== 1 ? "s" : ""}
                        </p>
                    </div>
                </div>

                {/* Grid / List */}
                <div className={cn(
                    "grid gap-6 animate-in fade-in zoom-in-95 duration-500",
                    viewMode === "grid"
                        ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"
                        : "grid-cols-1"
                )}>

                    {/* New Project Card */}
                    <ProCard
                        isNew
                        onClick={() => router.push('/capture')}
                    />

                    {/* Project Cards */}
                    {filteredProjects.map((project) => (
                        <ProCard
                            key={project.id}
                            project={project}
                            onClick={() => router.push(`/workspace/${project.id}`)}
                            onSettings={() => {
                                setSettingsProject(project);
                                setSettingsOpen(true);
                            }}
                        />
                    ))}
                </div>
            </div>

            {/* Floating Command Dock */}
            <FloatingDock
                viewMode={viewMode}
                setViewMode={setViewMode}
                searchQuery={searchQuery}
                setSearchQuery={setSearchQuery}
                activeFilter={activeFilter}
                setActiveFilter={setActiveFilter}
                sortBy={sortBy}
                setSortBy={setSortBy}
                onNewProject={() => router.push('/capture')}
            />

            {/* Dossier Settings Dialog */}
            {settingsProject && (
                <DossierSettingsDialog
                    project={settingsProject}
                    open={settingsOpen}
                    onOpenChange={setSettingsOpen}
                    onSave={handleSaveSettings}
                />
            )}
        </div>
    );
}
```

### 2. `src/components/workspace/pro-card.tsx` - Card Component
```typescript
"use client";

import { cn } from "@/lib/utils";
import { Folder, Clock, Plus, Settings, ArrowUpRight } from "lucide-react";
import { DecisionBadge } from "@/components/ui/decision-badge";

interface Project {
    id: string;
    title?: string;
    text: string;
    description?: string;
    globalScore?: number;
    recommendation?: string;
    timestamp: string;
    color?: string;
}

interface ProCardProps {
    project?: Project;
    isNew?: boolean;
    onClick?: () => void;
    onSettings?: (e: React.MouseEvent) => void;
    className?: string;
}

// Decision color mapping for top accent band
const DECISION_COLORS: Record<string, string> = {
    GO: "#10B981",
    EXPLORE: "#F59E0B",
    PARK: "#6B7280",
    KILL: "#EF4444",
    DRAFT: "#5D5C5B",
};

export function ProCard({ project, isNew, onClick, onSettings, className }: ProCardProps) {
    if (isNew) {
        return (
            <div
                onClick={onClick}
                className={cn(
                    "group relative w-full aspect-[4/3] cursor-pointer",
                    "bg-[--color-bg-card] rounded-[--radius-2xl] border border-dashed border-[--color-border-default]",
                    "hover:border-[--color-border-strong] hover:bg-[--color-bg-card-hover]",
                    "transition-all duration-200 flex flex-col items-center justify-center gap-4",
                    className
                )}
            >
                <div className="h-12 w-12 rounded-full bg-[--color-bg-card-hover] border border-[--color-border-default] flex items-center justify-center group-hover:border-[--color-border-strong] transition-all duration-300">
                    <Plus className="w-5 h-5 text-[--color-text-muted] group-hover:text-[--color-text-primary] transition-colors" />
                </div>
                <span className="text-xs font-bold text-[--color-text-muted] group-hover:text-[--color-text-secondary] uppercase tracking-widest transition-colors">
                    Nouveau Projet
                </span>
            </div>
        );
    }

    if (!project) return null;

    const decision = project.recommendation || "DRAFT";
    const score = project.globalScore || 0;
    const accentColor = project.color || DECISION_COLORS[decision] || DECISION_COLORS.DRAFT;

    return (
        <div
            onClick={onClick}
            className={cn(
                "group relative w-full aspect-[4/3] cursor-pointer",
                "bg-[--color-bg-card] rounded-[--radius-2xl] border border-[--color-border-default] overflow-hidden",
                "hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong]",
                "transition-all duration-300",
                className
            )}
        >
            {/* Color accent band at top */}
            <div
                className="absolute top-0 left-0 right-0 h-[3px]"
                style={{ backgroundColor: accentColor }}
            />

            {/* Settings button — top right, appears on hover */}
            {onSettings && (
                <button
                    onClick={(e) => {
                        e.stopPropagation();
                        onSettings(e);
                    }}
                    className="absolute top-4 right-4 z-20 opacity-0 group-hover:opacity-100 transition-opacity duration-200 h-8 w-8 rounded-full bg-black/40 backdrop-blur-sm flex items-center justify-center text-[--color-text-muted] hover:text-[--color-text-primary]"
                >
                    <Settings className="w-3.5 h-3.5" />
                </button>
            )}

            <div className="p-8 flex flex-col h-full relative z-10">
                {/* Header: Folder icon + Score */}
                <div className="flex justify-between items-start mb-4">
                    <div
                        className="h-10 w-10 rounded-xl bg-[--color-bg-card-hover] flex items-center justify-center"
                        style={{ borderColor: accentColor }}
                    >
                        <Folder className="w-4 h-4 text-[--color-text-muted]" />
                    </div>

                    {/* Score with /100 context */}
                    <div className="text-right">
                        <span className={cn(
                            "text-2xl font-light tabular-nums tracking-tight",
                            score >= 70 ? "text-[--color-text-primary]" : "text-[--color-text-secondary]"
                        )}>
                            {score}
                        </span>
                        <span className="text-xs text-[--color-text-muted] ml-0.5">/100</span>
                    </div>
                </div>

                {/* Body */}
                <div className="mt-2 mb-auto">
                    <h3 className="text-lg font-semibold text-[--color-text-primary] leading-tight mb-2 line-clamp-2 group-hover:text-[--color-text-primary] transition-colors">
                        {project.title || project.text}
                    </h3>
                    <p className="text-sm text-[--color-text-muted] line-clamp-3 leading-relaxed">
                        {project.description || "Aucune description disponible."}
                    </p>
                </div>

                {/* Footer: Date + Badge */}
                <div className="mt-4 pt-4 border-t border-[--color-border-subtle] flex items-center justify-between">
                    <span className="flex items-center gap-2 text-[10px] font-medium text-[--color-text-muted] group-hover:text-[--color-text-secondary] transition-colors uppercase tracking-wider">
                        <Clock className="w-3 h-3" />
                        {new Date(project.timestamp).toLocaleDateString()}
                    </span>
                    <div className="flex items-center gap-2">
                        <DecisionBadge decision={decision} className="text-[10px] px-2 py-0.5" />
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                            <ArrowUpRight className="w-4 h-4 text-[--color-text-secondary]" />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
```

### 3. `src/components/workspace/floating-dock.tsx` - Floating Dock Component
```typescript
"use client";

import { cn } from "@/lib/utils";
import {
    LayoutGrid,
    List,
    Search,
    ArrowUpDown,
    Plus
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useState } from "react";
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from "@/components/ui/tooltip";

interface FloatingDockProps {
    className?: string;
    viewMode: "grid" | "list";
    setViewMode: (mode: "grid" | "list") => void;
    searchQuery: string;
    setSearchQuery: (query: string) => void;
    activeFilter: string;
    setActiveFilter: (filter: string) => void;
    sortBy?: string;
    setSortBy?: (sort: string) => void;
    onNewProject: () => void;
}

const FILTERS = [
    { id: "ALL", label: "Tous", color: null },
    { id: "GO", label: "Go", color: "emerald" },
    { id: "EXPLORE", label: "Explore", color: "amber" },
    { id: "PARK", label: "Park", color: "gray" },
    { id: "KILL", label: "Kill", color: "red" },
];

const FILTER_ACTIVE_STYLES: Record<string, string> = {
    ALL: "bg-white/10 text-white border-[--color-border-strong]",
    GO: "bg-emerald-500/10 text-emerald-400 border-emerald-500/20",
    EXPLORE: "bg-amber-500/10 text-amber-400 border-amber-500/20",
    PARK: "bg-gray-500/10 text-gray-400 border-gray-500/20",
    KILL: "bg-red-500/10 text-red-400 border-red-500/20",
};

export function FloatingDock({
    className,
    viewMode,
    setViewMode,
    searchQuery,
    setSearchQuery,
    activeFilter,
    setActiveFilter,
    sortBy,
    setSortBy,
    onNewProject
}: FloatingDockProps) {
    const [isSearchOpen, setIsSearchOpen] = useState(false);

    return (
        <div className={cn(
            "fixed bottom-8 left-1/2 -translate-x-1/2 z-50",
            "flex items-center gap-3 p-2 rounded-[--radius-2xl]",
            "bg-[--color-bg-card]/80 backdrop-blur-2xl border border-[--color-border-default] shadow-lg",
            "transition-all duration-300",
            className
        )}>
            {/* View Toggles */}
            <div className="flex p-1 bg-[--color-bg-secondary] rounded-xl border border-[--color-border-subtle]">
                <TooltipProvider>
                    <Tooltip>
                        <TooltipTrigger asChild>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setViewMode("grid")}
                                className={cn(
                                    "h-10 w-10 rounded-lg",
                                    viewMode === "grid"
                                        ? "bg-[--color-border-default] text-[--color-text-primary]"
                                        : "text-[--color-text-muted] hover:text-[--color-text-primary]"
                                )}
                            >
                                <LayoutGrid className="w-5 h-5" />
                            </Button>
                        </TooltipTrigger>
                        <TooltipContent><p>Vue Grille</p></TooltipContent>
                    </Tooltip>
                </TooltipProvider>

                <TooltipProvider>
                    <Tooltip>
                        <TooltipTrigger asChild>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setViewMode("list")}
                                className={cn(
                                    "h-10 w-10 rounded-lg",
                                    viewMode === "list"
                                        ? "bg-[--color-border-default] text-[--color-text-primary]"
                                        : "text-[--color-text-muted] hover:text-[--color-text-primary]"
                                )}
                            >
                                <List className="w-5 h-5" />
                            </Button>
                        </TooltipTrigger>
                        <TooltipContent><p>Vue Liste</p></TooltipContent>
                    </Tooltip>
                </TooltipProvider>
            </div>

            <div className="w-px h-8 bg-[--color-border-default]" />

            {/* Filters — with decision colors */}
            <div className="hidden md:flex items-center gap-1">
                {FILTERS.map((f) => (
                    <button
                        key={f.id}
                        onClick={() => setActiveFilter(f.id)}
                        className={cn(
                            "px-3.5 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest border transition-all duration-200",
                            activeFilter === f.id
                                ? FILTER_ACTIVE_STYLES[f.id]
                                : "border-transparent text-[--color-text-muted] hover:text-[--color-text-secondary] hover:bg-[--color-bg-secondary]"
                        )}
                    >
                        {f.label}
                    </button>
                ))}
            </div>

            <div className="w-px h-8 bg-[--color-border-default] hidden md:block" />

            {/* Sort toggle */}
            {setSortBy && (
                <>
                    <TooltipProvider>
                        <Tooltip>
                            <TooltipTrigger asChild>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => setSortBy(sortBy === "date" ? "score" : "date")}
                                    className="h-10 w-10 text-[--color-text-muted] hover:text-[--color-text-primary]"
                                >
                                    <ArrowUpDown className="w-4 h-4" />
                                </Button>
                            </TooltipTrigger>
                            <TooltipContent>
                                <p>Trier par {sortBy === "date" ? "score" : "date"}</p>
                            </TooltipContent>
                        </Tooltip>
                    </TooltipProvider>
                    <div className="w-px h-8 bg-[--color-border-default]" />
                </>
            )}

            {/* Search */}
            <div className={cn(
                "relative flex items-center transition-all duration-300 overflow-hidden",
                isSearchOpen ? "w-64" : "w-10"
            )}>
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setIsSearchOpen(!isSearchOpen)}
                    className="absolute left-0 z-10 h-10 w-10 text-[--color-text-muted] hover:text-[--color-text-primary]"
                >
                    <Search className="w-5 h-5" />
                </Button>
                <Input
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="Rechercher..."
                    className={cn(
                        "h-10 border-none bg-[--color-bg-secondary] text-[--color-text-primary] pl-10 pr-4 transition-all duration-300",
                        isSearchOpen ? "opacity-100 w-full" : "opacity-0 w-0 pointer-events-none"
                    )}
                    autoFocus={isSearchOpen}
                />
            </div>

            {/* Main Action */}
            <Button
                onClick={onNewProject}
                className="ml-2 h-12 w-12 rounded-xl bg-[--color-brand-primary] text-white shadow-glow hover:bg-[--color-brand-secondary] hover:scale-105 hover:-translate-y-[1px] transition-all p-0"
            >
                <Plus className="w-6 h-6" />
            </Button>

        </div>
    );
}
```

### 4. `src/components/workspace/dossier-settings-dialog.tsx` - Settings Dialog
```typescript
"use client";

import { useState, useEffect } from "react";
import { cn } from "@/lib/utils";
import { Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { DecisionBadge } from "@/components/ui/decision-badge";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from "@/components/ui/dialog";
import { useLanguageStore } from "@/store/language-store";

const COLOR_PRESETS = [
    { hex: "#6B7280", label: "Gray" },
    { hex: "#F75105", label: "Orange" },
    { hex: "#3B82F6", label: "Blue" },
    { hex: "#8B5CF6", label: "Violet" },
    { hex: "#10B981", label: "Emerald" },
    { hex: "#F59E0B", label: "Amber" },
    { hex: "#EF4444", label: "Red" },
    { hex: "#EC4899", label: "Pink" },
];

interface DossierProject {
    id: string;
    title?: string;
    text: string;
    description?: string;
    color?: string;
    globalScore?: number;
    recommendation?: string;
    viabilityScore?: number;
    classification?: string;
}

interface DossierSettingsDialogProps {
    project: DossierProject;
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSave: (updates: { title?: string; description?: string; color?: string }) => void;
}

export function DossierSettingsDialog({ project, open, onOpenChange, onSave }: DossierSettingsDialogProps) {
    const { t } = useLanguageStore();
    const d = (t?.workspace as any)?.dossiers;

    const [title, setTitle] = useState(project.title || project.text || "");
    const [description, setDescription] = useState(project.description || "");
    const [color, setColor] = useState(project.color || "#6B7280");

    useEffect(() => {
        setTitle(project.title || project.text || "");
        setDescription(project.description || "");
        setColor(project.color || "#6B7280");
    }, [project]);

    const score = project.globalScore ?? project.viabilityScore;
    const decision = project.recommendation ?? project.classification ?? "DRAFT";

    function handleSave() {
        onSave({ title, description, color });
        onOpenChange(false);
    }

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="bg-[--color-bg-card] border border-[--color-border-default] rounded-[24px] max-w-md p-0 gap-0">
                <DialogHeader className="p-8 pb-0">
                    <DialogTitle className="text-white text-lg font-semibold">
                        {d?.settingsTitle || "Dossier Settings"}
                    </DialogTitle>
                </DialogHeader>

                <div className="space-y-6 p-8">
                    {/* Title */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                            {d?.titleLabel || "Title"}
                        </label>
                        <Input
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            className="h-10 bg-[--color-bg-secondary] border-[--color-border-default] text-white rounded-md focus:border-[#F75105] focus:ring-[3px] focus:ring-[rgba(247,81,5,0.1)]"
                        />
                    </div>

                    {/* Description */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                            {d?.descriptionLabel || "Description"}
                        </label>
                        <textarea
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder={d?.descriptionPlaceholder || "Add a description..."}
                            rows={3}
                            className="w-full bg-[--color-bg-secondary] border border-[--color-border-default] text-white rounded-md px-3 py-2 text-sm placeholder:text-[#5D5C5B] focus:border-[#F75105] focus:ring-[3px] focus:ring-[rgba(247,81,5,0.1)] focus:outline-none resize-none"
                        />
                    </div>

                    {/* Score & Decision (read-only) */}
                    {score !== undefined && (
                        <div className="space-y-2">
                            <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                                {d?.scoreLabel || "Score"}
                            </label>
                            <div className="flex items-center gap-4 p-4 bg-[--color-bg-secondary] rounded-md border border-[--color-border-default]">
                                <span className={cn(
