"use client";

import { cn } from "@/lib/utils";
import { Folder, Clock, Plus, Settings, ArrowUpRight } from "lucide-react";
import { DecisionBadge } from "@/components/ui/decision-badge";

interface Project {
    id: string;
    title?: string;
    text: string;
    description?: string;
    globalScore?: number;
    recommendation?: string;
    timestamp: string;
    color?: string;
}

interface ProCardProps {
    project?: Project;
    isNew?: boolean;
    onClick?: () => void;
    onSettings?: (e: React.MouseEvent) => void;
    className?: string;
}

// Decision color mapping for top accent band
const DECISION_COLORS: Record<string, string> = {
    GO: "#10B981",
    EXPLORE: "#F59E0B",
    PARK: "#6B7280",
    KILL: "#EF4444",
    DRAFT: "#5D5C5B",
};

export function ProCard({ project, isNew, onClick, onSettings, className }: ProCardProps) {
    if (isNew) {
        return (
            <div
                onClick={onClick}
                className={cn(
                    "group relative w-full aspect-[4/3] cursor-pointer",
                    "bg-[--color-bg-card] rounded-[--radius-2xl] border border-dashed border-[--color-border-default]",
                    "hover:border-[--color-border-strong] hover:bg-[--color-bg-card-hover]",
                    "transition-all duration-200 flex flex-col items-center justify-center gap-4",
                    className
                )}
            >
                <div className="h-12 w-12 rounded-full bg-[--color-bg-card-hover] border border-[--color-border-default] flex items-center justify-center group-hover:border-[--color-border-strong] transition-all duration-300">
                    <Plus className="w-5 h-5 text-[--color-text-muted] group-hover:text-[--color-text-primary] transition-colors" />
                </div>
                <span className="text-xs font-bold text-[--color-text-muted] group-hover:text-[--color-text-secondary] uppercase tracking-widest transition-colors">
                    Nouveau Projet
                </span>
            </div>
        );
    }

    if (!project) return null;

    const decision = project.recommendation || "DRAFT";
    const score = project.globalScore || 0;
    const accentColor = project.color || DECISION_COLORS[decision] || DECISION_COLORS.DRAFT;

    return (
        <div
            onClick={onClick}
