                style={{ backgroundColor: accentColor }}
            />

            {/* Settings button — top right, appears on hover */}
            {onSettings && (
                <button
                    onClick={(e) => {
                        e.stopPropagation();
                        onSettings(e);
                    }}
                    className="absolute top-4 right-4 z-20 opacity-0 group-hover:opacity-100 transition-opacity duration-200 h-8 w-8 rounded-full bg-black/40 backdrop-blur-sm flex items-center justify-center text-[--color-text-muted] hover:text-[--color-text-primary]"
                >
                    <Settings className="w-3.5 h-3.5" />
                </button>
            )}

            <div className="p-8 flex flex-col h-full relative z-10">
                {/* Header: Folder icon + Score */}
                <div className="flex justify-between items-start mb-4">
                    <div
