            <div className="w-px h-8 bg-[--color-border-default]" />

            {/* Filters — with decision colors */}
            <div className="hidden md:flex items-center gap-1">
                {FILTERS.map((f) => (
                    <button
                        key={f.id}
                        onClick={() => setActiveFilter(f.id)}
                        className={cn(
                            "px-3.5 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest border transition-all duration-200",
                            activeFilter === f.id
                                ? FILTER_ACTIVE_STYLES[f.id]
                                : "border-transparent text-[--color-text-muted] hover:text-[--color-text-secondary] hover:bg-[--color-bg-secondary]"
                        )}
                    >
                        {f.label}
                    </button>
                ))}
            </div>

            <div className="w-px h-8 bg-[--color-border-default] hidden md:block" />

            {/* Sort toggle */}
            {setSortBy && (
                <>
                    <TooltipProvider>
                        <Tooltip>
                            <TooltipTrigger asChild>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => setSortBy(sortBy === "date" ? "score" : "date")}
                                    className="h-10 w-10 text-[--color-text-muted] hover:text-[--color-text-primary]"
                                >
                                    <ArrowUpDown className="w-4 h-4" />
                                </Button>
                            </TooltipTrigger>
                            <TooltipContent>
                                <p>Trier par {sortBy === "date" ? "score" : "date"}</p>
                            </TooltipContent>
                        </Tooltip>
                    </TooltipProvider>
                    <div className="w-px h-8 bg-[--color-border-default]" />
                </>
            )}

            {/* Search */}
            <div className={cn(
                "relative flex items-center transition-all duration-300 overflow-hidden",
                isSearchOpen ? "w-64" : "w-10"
            )}>
                <Button
                    variant="ghost"
                    size="icon"
                    onClick={() => setIsSearchOpen(!isSearchOpen)}
                    className="absolute left-0 z-10 h-10 w-10 text-[--color-text-muted] hover:text-[--color-text-primary]"
                >
                    <Search className="w-5 h-5" />
                </Button>
                <Input
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="Rechercher..."
                    className={cn(
                        "h-10 border-none bg-[--color-bg-secondary] text-[--color-text-primary] pl-10 pr-4 transition-all duration-300",
                        isSearchOpen ? "opacity-100 w-full" : "opacity-0 w-0 pointer-events-none"
                    )}
                    autoFocus={isSearchOpen}
                />
            </div>

            {/* Main Action */}
            <Button
                onClick={onNewProject}
                className="ml-2 h-12 w-12 rounded-xl bg-[--color-brand-primary] text-white shadow-glow hover:bg-[--color-brand-secondary] hover:scale-105 hover:-translate-y-[1px] transition-all p-0"
            >
                <Plus className="w-6 h-6" />
            </Button>

        </div>
    );
}
