### 4. `src/components/workspace/dossier-settings-dialog.tsx` - Settings Dialog
```typescript
"use client";

import { useState, useEffect } from "react";
import { cn } from "@/lib/utils";
import { Check } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { DecisionBadge } from "@/components/ui/decision-badge";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from "@/components/ui/dialog";
import { useLanguageStore } from "@/store/language-store";

const COLOR_PRESETS = [
    { hex: "#6B7280", label: "Gray" },
    { hex: "#F75105", label: "Orange" },
    { hex: "#3B82F6", label: "Blue" },
    { hex: "#8B5CF6", label: "Violet" },
    { hex: "#10B981", label: "Emerald" },
    { hex: "#F59E0B", label: "Amber" },
    { hex: "#EF4444", label: "Red" },
    { hex: "#EC4899", label: "Pink" },
];

interface DossierProject {
    id: string;
    title?: string;
    text: string;
    description?: string;
    color?: string;
    globalScore?: number;
    recommendation?: string;
    viabilityScore?: number;
    classification?: string;
}

interface DossierSettingsDialogProps {
    project: DossierProject;
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSave: (updates: { title?: string; description?: string; color?: string }) => void;
}

export function DossierSettingsDialog({ project, open, onOpenChange, onSave }: DossierSettingsDialogProps) {
    const { t } = useLanguageStore();
    const d = (t?.workspace as any)?.dossiers;

    const [title, setTitle] = useState(project.title || project.text || "");
    const [description, setDescription] = useState(project.description || "");
    const [color, setColor] = useState(project.color || "#6B7280");

    useEffect(() => {
        setTitle(project.title || project.text || "");
        setDescription(project.description || "");
        setColor(project.color || "#6B7280");
    }, [project]);

    const score = project.globalScore ?? project.viabilityScore;
    const decision = project.recommendation ?? project.classification ?? "DRAFT";

    function handleSave() {
        onSave({ title, description, color });
        onOpenChange(false);
    }

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="bg-[--color-bg-card] border border-[--color-border-default] rounded-[24px] max-w-md p-0 gap-0">
                <DialogHeader className="p-8 pb-0">
                    <DialogTitle className="text-white text-lg font-semibold">
                        {d?.settingsTitle || "Dossier Settings"}
                    </DialogTitle>
                </DialogHeader>

                <div className="space-y-6 p-8">
                    {/* Title */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                            {d?.titleLabel || "Title"}
                        </label>
                        <Input
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            className="h-10 bg-[--color-bg-secondary] border-[--color-border-default] text-white rounded-md focus:border-[#F75105] focus:ring-[3px] focus:ring-[rgba(247,81,5,0.1)]"
                        />
                    </div>

                    {/* Description */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                            {d?.descriptionLabel || "Description"}
                        </label>
                        <textarea
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder={d?.descriptionPlaceholder || "Add a description..."}
                            rows={3}
                            className="w-full bg-[--color-bg-secondary] border border-[--color-border-default] text-white rounded-md px-3 py-2 text-sm placeholder:text-[#5D5C5B] focus:border-[#F75105] focus:ring-[3px] focus:ring-[rgba(247,81,5,0.1)] focus:outline-none resize-none"
                        />
                    </div>

                    {/* Score & Decision (read-only) */}
                    {score !== undefined && (
                        <div className="space-y-2">
                            <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                                {d?.scoreLabel || "Score"}
                            </label>
                            <div className="flex items-center gap-4 p-4 bg-[--color-bg-secondary] rounded-md border border-[--color-border-default]">
                                <span className={cn(
                                    "text-2xl font-light tabular-nums",
                                    score >= 70 ? "text-white" : "text-[#D2D3D4]"
                                )}>
                                    {score}<span className="text-sm text-[#5D5C5B] ml-0.5">/100</span>
                                </span>
                                <DecisionBadge decision={decision} />
                            </div>
                        </div>
                    )}

                    {/* Color Picker */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-[0.1em] text-[#F75105]">
                            {d?.colorLabel || "Color"}
                        </label>
                        <div className="flex gap-2.5">
                            {COLOR_PRESETS.map((preset) => (
                                <button
                                    key={preset.hex}
                                    onClick={() => setColor(preset.hex)}
                                    className={cn(
                                        "w-8 h-8 rounded-full border-2 flex items-center justify-center transition-colors",
                                        color === preset.hex
                                            ? "border-white"
                                            : "border-transparent hover:border-[--color-border-strong]"
                                    )}
                                    style={{ backgroundColor: preset.hex }}
                                    title={preset.label}
                                >
                                    {color === preset.hex && <Check className="w-3.5 h-3.5 text-white" />}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                <DialogFooter className="p-8 pt-0">
                    <Button
                        variant="outline"
                        onClick={() => onOpenChange(false)}
                        className="bg-transparent border-[--color-border-default] text-[#D2D3D4] hover:bg-[--color-bg-card-hover] hover:border-[--color-border-strong] hover:text-white"
                    >
                        {d?.cancel || "Cancel"}
                    </Button>
                    <Button
                        onClick={handleSave}
                        className="bg-[#F75105] hover:bg-[#F78E21] text-white hover:shadow-[--shadow-glow] hover:-translate-y-[1px] transition-all"
                    >
                        {d?.save || "Save"}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}
